Value.Calculation:
Let (
	~override = JSONGetElement ( $input ; "solution_name" ) ;
	If ( IsEmpty ( ~override ) ; Get ( FileName ) ; ~override )
)

Step.Calculation:
JSONSetElement ( "{}" ;
	[ "success" ; False ; JSONBoolean ] ;
	[ "error" ; "Save as XML failed (error " & $saveError & ")" ; JSONString ]
)

JSONSetElement ( "{}" ;
	[ "success" ; False ; JSONBoolean ] ;
	[ "error" ; "Companion server unreachable (error " & $httpError & ")" ; JSONString ]
)

Value.Calculation:
JSONSetElement ( "{}" ;
	[ "solution_name" ; Get ( FileName ) ; JSONString ] ;
	[ "export_file_path" ; ConvertFromFileMakerPath ( $output ; 1 ) ; JSONString ] ;
	[ "repo_path" ; ConvertFromFileMakerPath ( JSONGetElement ( $$AGENTIC.FM ; "path" ) ; 1 ) ; JSONString ] ;
	[ "exploder_bin_path" ; "~/bin/fm-xml-export-exploder" ; JSONString ]
)

Step.Calculation:
JSONSetElement ( "{}" ;
	[ "success" ; False ; JSONBoolean ] ;
	[ "error" ; "Companion server unreachable (error " & $httpError & ")" ; JSONString ]
)

Value.Calculation:
JSONSetElement ( $context ;
	[ "snapshot_path" ; "agent/context/snapshot.xml" ; JSONString ] ;
	[ "snapshot_timestamp" ; GetAsText ( Get ( CurrentTimestamp ) ) ; JSONString ]
)

Step.Calculation:
JSONSetElement ( "{}" ;
	[ "success" ; False ; JSONBoolean ] ;
	[ "error" ; "Missing required key: layout" ; JSONString ]
)

JSONSetElement ( "{}" ;
	[ "success" ; True ; JSONBoolean ] ;
	[ "layout" ; Get ( LayoutName ) ; JSONString ] ;
	[ "tableOccurrence" ; Get ( LayoutTableName ) ; JSONString ]
)

Value.Calculation:
JSONSetElement ( "{}" ;
	[ "script" ; "Push Context" ; JSONString ] ;
	[ "parameter" ; "build invoice scripts" ; JSONString ]
)

Step.Calculation:
JSONSetElement ( "{}" ;
	[ "success" ; False ; JSONBoolean ] ;
	[ "error" ; "Invalid parameter: expected JSON object" ; JSONString ]
)

JSONSetElement ( "{}" ;
	[ "success" ; False ; JSONBoolean ] ;
	[ "error" ; "Script not found: " & $script ; JSONString ]
)

JSONSetElement ( "{}" ;
	[ "success" ; False ; JSONBoolean ] ;
	[ "error" ; "Invalid parameter: expected JSON object" ; JSONString ]
)

JSONSetElement ( "{}" ;
	[ "success" ; False ; JSONBoolean ] ;
	[ "error" ; "Missing required key: expression" ; JSONString ]
)

JSONSetElement ( "{}" ;
	[ "success" ; False ; JSONBoolean ] ;
	[ "error_code" ; $gotoError ; JSONNumber ] ;
	[ "error" ; "Go to Layout failed — layout not found: " & $layout ; JSONString ] ;
	[ "expression" ; $expression ; JSONString ]
)

JSONSetElement ( "{}" ;
	[ "success" ; $errorCode = 0 ; JSONBoolean ] ;
	[ "error_code" ; $errorCode ; JSONNumber ] ;
	[ "result" ; $result ; JSONString ] ;
	[ "expression" ; $expression ; JSONString ] ;
	[ "layout" ; Get ( LayoutName ) ; JSONString ]
)

JSONSetElement ( "{}" ;
	[ "success" ; False ; JSONBoolean ] ;
	[ "error" ; "No pending job — companion /pending returned empty" ; JSONString ]
)

Value.Calculation:
JSONSetElement ( "{}" ;
	[ "lastError" ; Get ( LastError ) ; JSONNumber ] ;
	[ "lastErrorLocation" ; Get ( LastErrorLocation ) ; JSONString ]
)

JSONSetElement ( "{}" ;
	[ "label" ; JSONGetElement ( $param ; "label" ) ; JSONString ] ;
	[ "vars" ; JSONGetElement ( $param ; "vars" ) ; JSONRaw ] ;
	[ "timestamp" ; Get ( CurrentTimestamp ) ; JSONString ] ;
	[ "lastError" ; JSONGetElement ( $errorContext ; "lastError" ) ; JSONNumber ] ;
	[ "lastErrorLocation" ; JSONGetElement ( $errorContext ; "lastErrorLocation" ) ; JSONString ]
)

Step.Calculation:
JSONSetElement ( "{}" ;
	[ "label" ; "after Insert from URL" ; JSONString ] ;
	[ "vars"  ; JSONSetElement ( "{}" ;
		[ "exitCode"  ; $exitCode  ; JSONString ] ;
		[ "httpError" ; $httpError ; JSONString ] ;
		[ "response"  ; $response  ; JSONString ]
	) ; JSONRaw ]
)
